exercises.solution_code:
#include <iostream>
#include <memory>

struct Logger {
    int id;
    Logger(int id) : id{id} {
        std::cout << "Logger " << id << " created\n";
    }
    void log() const {
        std::cout << "Logger " << id << " logging\n";
    }
    ~Logger() {
        std::cout << "Logger " << id << " destroyed\n";
    }
};

int main() {
    int id{};
    std::cin >> id;

    auto original = std::make_unique<Logger>(id);
    original->log();

    auto newOwner = std::move(original);
    std::cout << "Transferred: original is null = "
              << std::boolalpha << (original == nullptr) << '\n';
    std::cout << "New owner has logger " << newOwner->id << '\n';

    return 0;
}

