exercises.solution_code:
#include <iostream>
#include <memory>
#include <vector>

struct Item {
    int id;
    Item(int id) : id{id} {
        std::cout << "Item " << id << " created\n";
    }
    ~Item() {
        std::cout << "Item " << id << " destroyed\n";
    }
};

int main() {
    int n{};
    int idx{};
    std::cin >> n >> idx;

    std::vector<std::unique_ptr<Item>> items;
    for (int i{1}; i <= n; ++i) {
        items.push_back(std::make_unique<Item>(i));
    }

    std::cout << "Vector size: " << items.size() << '\n';

    auto extracted = std::move(items[static_cast<std::size_t>(idx)]);
    std::cout << "Extracted item " << extracted->id << '\n';
    std::cout << "Vector size after extract: " << items.size() << '\n';

    return 0;
}
